-- Game Developer Roadmap seed.
-- Idempotent seed. Safe to rerun.
BEGIN;
CREATE EXTENSION IF NOT EXISTS pgcrypto;

DROP TABLE IF EXISTS seed_edge;
DROP TABLE IF EXISTS seed_node_resource;
DROP TABLE IF EXISTS seed_node_skill;
DROP TABLE IF EXISTS seed_node;
DROP TABLE IF EXISTS seed_resource;
DROP TABLE IF EXISTS seed_skill;
DROP TABLE IF EXISTS seed_roadmap_map;

DELETE FROM public.progress_event WHERE roadmap_enrollment_id IN (SELECT e.roadmap_enrollment_id FROM public.roadmap_enrollment e JOIN public.roadmap_version rv ON rv.roadmap_version_id = e.roadmap_version_id JOIN public.roadmap r ON r.roadmap_id = rv.roadmap_id WHERE r.slug = 'game-developer-roadmap');
DELETE FROM public.user_node_progress WHERE roadmap_enrollment_id IN (SELECT e.roadmap_enrollment_id FROM public.roadmap_enrollment e JOIN public.roadmap_version rv ON rv.roadmap_version_id = e.roadmap_version_id JOIN public.roadmap r ON r.roadmap_id = rv.roadmap_id WHERE r.slug = 'game-developer-roadmap');
DELETE FROM public.roadmap_enrollment WHERE roadmap_version_id IN (SELECT rv.roadmap_version_id FROM public.roadmap_version rv JOIN public.roadmap r ON r.roadmap_id = rv.roadmap_id WHERE r.slug = 'game-developer-roadmap');
DELETE FROM public.roadmap WHERE slug = 'game-developer-roadmap';

    'Game Developer',
    'game-developer',
    'Game developer path covering programming, engines, game math, physics, graphics, gameplay systems, UI, audio, AI, multiplayer, optimization, publishing, and portfolio-ready production.',
    'Game Development',
    true
) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, category = EXCLUDED.category, is_active = true, updated_at = now();

DROP TABLE IF EXISTS seed_roadmap_map;
CREATE TEMP TABLE seed_roadmap_map AS
WITH role_row AS (SELECT career_role_id FROM public.career_role WHERE slug = 'game-developer'), inserted_roadmap AS (
SELECT career_role_id, (SELECT user_id FROM public."user" WHERE username_normalized = 'contentmanager2' LIMIT 1), 'Game Developer Roadmap', 'game-developer-roadmap', 'A structured learning path for becoming a game developer, covering game programming, engines, math, physics, graphics, gameplay systems, UI, audio, AI, multiplayer, optimization, publishing, and portfolio-ready production.', 'public'
FROM role_row
    RETURNING roadmap_id
), inserted_version AS (
SELECT
    roadmap_id,
    1,
    1,
    0,
    0,
    'initial',
    'published',
    'Game Developer Roadmap',
    'A practical game development roadmap that moves from foundations to shippable portfolio work through engine skills, guided topics, checkpoints, optional practice projects, and required milestone projects.',
    420,
    'TB',
    'custom',
    now()
FROM inserted_roadmap
    RETURNING roadmap_version_id, roadmap_id
) SELECT roadmap_id, roadmap_version_id FROM inserted_version;

-- Skills.
-- Roadmap-specific skills are intentionally consolidated and reusable.
-- Shared canonical skills are referenced from shared-skills.seed.sql.
DROP TABLE IF EXISTS seed_skill;
CREATE TEMP TABLE seed_skill (
    slug text PRIMARY KEY,
    name text NOT NULL,
    category text NOT NULL,
    description text NOT NULL
) ON COMMIT DROP;


-- Keep roadmap-owned skill definitions current on reruns.
UPDATE public.skill s
SET name = ss.name,
    category = ss.category,
    description = ss.description,
    is_active = true
FROM seed_skill ss
WHERE s.slug = ss.slug;

-- Reuse an existing row with the same canonical name when a legacy slug exists.
UPDATE public.skill s
SET category = ss.category,
    description = ss.description,
    is_active = true
FROM seed_skill ss
WHERE s.name = ss.name
  AND NOT EXISTS (
      SELECT 1
      FROM public.skill canonical
      WHERE canonical.slug = ss.slug
  );

SELECT ss.name, ss.slug, ss.category, ss.description, true
FROM seed_skill ss
WHERE NOT EXISTS (
    SELECT 1
    FROM public.skill s
    WHERE s.slug = ss.slug OR s.name = ss.name
);

-- Learning resources.
DROP TABLE IF EXISTS seed_resource;
CREATE TEMP TABLE seed_resource (resource_key text PRIMARY KEY, title text NOT NULL, url text NOT NULL, resource_type text NOT NULL, description text NOT NULL, provider text, difficulty_level text) ON COMMIT DROP;

UPDATE public.learning_resource lr
SET title = sr.title,
    resource_type = sr.resource_type,
    description = sr.description,
    provider = sr.provider,
    difficulty_level = sr.difficulty_level,
    language_code = 'en',
    verification_status = 'verified',
    updated_at = now()
FROM (SELECT DISTINCT ON (url) * FROM seed_resource ORDER BY url, resource_key) sr
WHERE lr.url = sr.url;

SELECT sr.title, sr.url, sr.resource_type, sr.description, sr.provider, sr.difficulty_level, 'en', 'verified'
FROM (SELECT DISTINCT ON (url) * FROM seed_resource ORDER BY url, resource_key) sr
WHERE NOT EXISTS (SELECT 1 FROM public.learning_resource lr WHERE lr.url = sr.url);

-- Roadmap nodes.
DROP TABLE IF EXISTS seed_node;
CREATE TEMP TABLE seed_node (
    node_key text PRIMARY KEY,
    parent_key text,
    node_type text NOT NULL,
    checkpoint_type text,
    selection_type text,
    required_count int,
    title text NOT NULL,
    description text NOT NULL,
    order_index int NOT NULL,
    layout_role text NOT NULL,
    estimated_hours int,
    difficulty_level text,
    metadata jsonb NOT NULL,
    is_required boolean NOT NULL,
    is_trackable boolean NOT NULL,
    learning_outcomes jsonb NOT NULL,
    completion_criteria jsonb NOT NULL
) ON COMMIT DROP;

SELECT m.roadmap_version_id, NULL, sn.node_key, sn.node_type, sn.checkpoint_type, sn.selection_type, sn.required_count, sn.title, sn.description, sn.order_index, sn.layout_role, sn.estimated_hours, sn.difficulty_level, sn.metadata, sn.is_required, sn.is_trackable, sn.learning_outcomes, sn.completion_criteria
FROM seed_node sn CROSS JOIN seed_roadmap_map m
ON CONFLICT (roadmap_version_id, slug) DO UPDATE SET
    node_type = EXCLUDED.node_type,
    checkpoint_type = EXCLUDED.checkpoint_type,
    selection_type = EXCLUDED.selection_type,
    required_count = EXCLUDED.required_count,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    order_index = EXCLUDED.order_index,
    layout_role = EXCLUDED.layout_role,
    estimated_hours = EXCLUDED.estimated_hours,
    difficulty_level = EXCLUDED.difficulty_level,
    metadata = EXCLUDED.metadata,
    is_required = EXCLUDED.is_required,
    is_trackable = EXCLUDED.is_trackable,
    learning_outcomes = EXCLUDED.learning_outcomes,
    completion_criteria = EXCLUDED.completion_criteria;

UPDATE public.roadmap_node child
SET parent_node_id = parent.roadmap_node_id
FROM seed_node sn
CROSS JOIN seed_roadmap_map m
JOIN public.roadmap_node parent ON parent.roadmap_version_id = m.roadmap_version_id AND parent.slug = sn.parent_key
WHERE child.roadmap_version_id = m.roadmap_version_id
  AND child.slug = sn.node_key
  AND sn.parent_key IS NOT NULL;

UPDATE public.roadmap_node child
SET parent_node_id = NULL
FROM seed_node sn
CROSS JOIN seed_roadmap_map m
WHERE child.roadmap_version_id = m.roadmap_version_id
  AND child.slug = sn.node_key
  AND sn.parent_key IS NULL;

-- Node-skill mappings.
-- Only topic, choice_option, and project nodes may own skill mappings.
DROP TABLE IF EXISTS seed_node_skill;
CREATE TEMP TABLE seed_node_skill (
    node_key text NOT NULL,
    skill_slug text NOT NULL,
    PRIMARY KEY (node_key, skill_slug)
) ON COMMIT DROP;

ON CONFLICT (node_key, skill_slug) DO NOTHING;

SELECT DISTINCT
    rn.roadmap_node_id, resolved_skill.skill_id
FROM seed_node_skill sns
JOIN seed_roadmap_map m
    ON true
JOIN public.roadmap_node rn
    ON rn.roadmap_version_id = m.roadmap_version_id
   AND rn.slug = sns.node_key
LEFT JOIN seed_skill ss
    ON ss.slug = sns.skill_slug
JOIN LATERAL (
    SELECT s.skill_id
    FROM public.skill s
    WHERE s.slug = sns.skill_slug
       OR (ss.name IS NOT NULL AND s.name = ss.name)
    ORDER BY
        CASE WHEN s.slug = sns.skill_slug THEN 0 ELSE 1 END
    LIMIT 1
) resolved_skill ON true
ON CONFLICT (roadmap_node_id, skill_id) DO NOTHING;

WITH duplicate_node_skill AS (
    SELECT
        rns.roadmap_node_skill_id,
        row_number() OVER (
            PARTITION BY rns.roadmap_node_id, rns.skill_id
            ORDER BY rns.roadmap_node_skill_id
        ) AS duplicate_rank
    FROM public.roadmap_node_skill rns
    JOIN public.roadmap_node rn ON rn.roadmap_node_id = rns.roadmap_node_id
    JOIN seed_roadmap_map m ON m.roadmap_version_id = rn.roadmap_version_id
)
DELETE FROM public.roadmap_node_skill rns
USING duplicate_node_skill dns
WHERE rns.roadmap_node_skill_id = dns.roadmap_node_skill_id
  AND dns.duplicate_rank > 1;

-- Node-resource mappings.
DROP TABLE IF EXISTS seed_node_resource;
CREATE TEMP TABLE seed_node_resource (
    node_key text NOT NULL,
    resource_key text NOT NULL,
    order_index int NOT NULL,
    PRIMARY KEY (node_key, resource_key)
) ON COMMIT DROP;
ON CONFLICT (node_key, resource_key) DO NOTHING;

WITH resolved_node_resource AS (
    SELECT DISTINCT ON (rn.roadmap_node_id, lower(lr.url))
        rn.roadmap_node_id,
        lr.learning_resource_id
    FROM seed_node_resource snr
    JOIN seed_node sn ON sn.node_key = snr.node_key
    JOIN seed_roadmap_map m ON true
    JOIN public.roadmap_node rn
        ON rn.roadmap_version_id = m.roadmap_version_id
       AND rn.slug = sn.node_key
    JOIN seed_resource sr ON sr.resource_key = snr.resource_key
    JOIN LATERAL (
        SELECT lr.learning_resource_id, lr.url
        FROM public.learning_resource lr
        WHERE lr.url = sr.url
        ORDER BY lr.learning_resource_id
        LIMIT 1
    ) lr ON true
    ORDER BY rn.roadmap_node_id, lower(lr.url), snr.order_index
)
SELECT roadmap_node_id, learning_resource_id
FROM resolved_node_resource
ON CONFLICT (roadmap_node_id, learning_resource_id) DO NOTHING;

WITH resolved_resource_skill AS (
    SELECT DISTINCT
        lr.learning_resource_id,
        s.skill_id
    FROM seed_node_resource snr
    JOIN seed_node_skill sns ON sns.node_key = snr.node_key
    JOIN seed_resource sr ON sr.resource_key = snr.resource_key
    JOIN LATERAL (
        SELECT lr.learning_resource_id
        FROM public.learning_resource lr
        WHERE lr.url = sr.url
        ORDER BY lr.learning_resource_id
        LIMIT 1
    ) lr ON true
    JOIN public.skill s ON s.slug = sns.skill_slug
)
SELECT learning_resource_id, skill_id
FROM resolved_resource_skill
ON CONFLICT (learning_resource_id, skill_id) DO NOTHING;

WITH duplicate_node_resource AS (
    SELECT
        rnr.roadmap_node_resource_id,
        row_number() OVER (
            PARTITION BY rnr.roadmap_node_id, lower(lr.url)
            ORDER BY rnr.roadmap_node_resource_id
        ) AS duplicate_rank
    FROM public.roadmap_node_resource rnr
    JOIN public.roadmap_node rn ON rn.roadmap_node_id = rnr.roadmap_node_id
    JOIN public.learning_resource lr ON lr.learning_resource_id = rnr.learning_resource_id
    JOIN seed_roadmap_map m ON m.roadmap_version_id = rn.roadmap_version_id
)
DELETE FROM public.roadmap_node_resource rnr
USING duplicate_node_resource dnr
WHERE rnr.roadmap_node_resource_id = dnr.roadmap_node_resource_id
  AND dnr.duplicate_rank > 1;

WITH duplicate_resource_skill AS (
    SELECT
        lrs.learning_resource_skill_id,
        row_number() OVER (
            PARTITION BY lower(lr.url), lrs.skill_id
            ORDER BY lrs.learning_resource_skill_id
        ) AS duplicate_rank
    FROM public.learning_resource_skill lrs
    JOIN public.learning_resource lr ON lr.learning_resource_id = lrs.learning_resource_id
    JOIN seed_resource sr ON sr.url = lr.url
)
DELETE FROM public.learning_resource_skill lrs
USING duplicate_resource_skill drs
WHERE lrs.learning_resource_skill_id = drs.learning_resource_skill_id
  AND drs.duplicate_rank > 1;

-- Edges.
DROP TABLE IF EXISTS seed_edge;
CREATE TEMP TABLE seed_edge (from_key text NOT NULL, to_key text NOT NULL, edge_type text NOT NULL, dependency_type text NOT NULL, condition jsonb NOT NULL, PRIMARY KEY (from_key, to_key, edge_type)) ON COMMIT DROP;
;

DELETE FROM public.roadmap_edge e
USING seed_roadmap_map m
WHERE e.roadmap_version_id = m.roadmap_version_id;

SELECT m.roadmap_version_id, source.roadmap_node_id, target.roadmap_node_id, se.edge_type, se.dependency_type, se.condition
FROM seed_edge se
CROSS JOIN seed_roadmap_map m
JOIN public.roadmap_node source ON source.roadmap_version_id = m.roadmap_version_id AND source.slug = se.from_key
JOIN public.roadmap_node target ON target.roadmap_version_id = m.roadmap_version_id AND target.slug = se.to_key
ON CONFLICT (roadmap_version_id, from_node_id, to_node_id, edge_type) DO UPDATE SET dependency_type = EXCLUDED.dependency_type,
    condition = EXCLUDED.condition;


-- Summary and invariant checks.
DO $$
DECLARE
    local_skill_count int;
    roadmap_skill_count int;
    category_count int;
    min_category_skill_count int;
    max_category_skill_count int;
    resource_count int;
    node_count int;
    node_skill_count int;
    node_resource_count int;
    edge_count int;
    invalid_node_skill_count int;
    unmapped_allowed_node_count int;
    missing_skill_reference_count int;
    required_trackable_hours int;
    all_trackable_hours int;
BEGIN
    SELECT COUNT(*) INTO local_skill_count FROM seed_skill;
    SELECT COUNT(DISTINCT skill_slug) INTO roadmap_skill_count FROM seed_node_skill;
    SELECT COUNT(*) INTO resource_count FROM seed_resource;
    SELECT COUNT(*) INTO node_count FROM seed_node;
    SELECT COUNT(*) INTO node_skill_count FROM seed_node_skill;
    SELECT COUNT(*) INTO node_resource_count FROM seed_node_resource;
    SELECT COUNT(*) INTO edge_count FROM seed_edge;

    SELECT COUNT(*)
    INTO invalid_node_skill_count
    FROM seed_node_skill sns
    JOIN seed_node sn ON sn.node_key = sns.node_key
    WHERE sn.node_type NOT IN ('topic', 'choice_option', 'project');

    SELECT COUNT(*)
    INTO unmapped_allowed_node_count
    FROM seed_node sn
    WHERE sn.node_type IN ('topic', 'choice_option', 'project')
      AND NOT EXISTS (
          SELECT 1
          FROM seed_node_skill sns
          WHERE sns.node_key = sn.node_key
      );

    SELECT COUNT(*)
    INTO missing_skill_reference_count
    FROM (
        SELECT DISTINCT skill_slug
        FROM seed_node_skill
    ) referenced
    LEFT JOIN seed_skill local_skill
        ON local_skill.slug = referenced.skill_slug
    LEFT JOIN public.skill shared_or_existing_skill
        ON shared_or_existing_skill.slug = referenced.skill_slug
    WHERE local_skill.slug IS NULL
      AND shared_or_existing_skill.skill_id IS NULL;

    WITH roadmap_skill AS (
        SELECT DISTINCT
            sns.skill_slug,
            COALESCE(local_skill.category, shared_skill.category) AS category
        FROM seed_node_skill sns
        LEFT JOIN seed_skill local_skill
            ON local_skill.slug = sns.skill_slug
        LEFT JOIN public.skill shared_skill
            ON shared_skill.slug = sns.skill_slug
    ),
    category_total AS (
        SELECT category, COUNT(*) AS skill_count
        FROM roadmap_skill
        GROUP BY category
    )
    SELECT
        COUNT(*),
        MIN(skill_count),
        MAX(skill_count)
    INTO
        category_count,
        min_category_skill_count,
        max_category_skill_count
    FROM category_total;

    SELECT COALESCE(SUM(estimated_hours), 0)
    INTO required_trackable_hours
    FROM seed_node
    WHERE is_required = true
      AND is_trackable = true;

    SELECT COALESCE(SUM(estimated_hours), 0)
    INTO all_trackable_hours
    FROM seed_node
    WHERE is_trackable = true;

    IF roadmap_skill_count NOT BETWEEN 90 AND 100 THEN
        RAISE EXCEPTION
            'Game Developer roadmap must map 90-100 distinct skills; found %.',
            roadmap_skill_count;
    END IF;

    IF invalid_node_skill_count <> 0 THEN
        RAISE EXCEPTION
            'Game Developer roadmap contains % skill mappings on forbidden node types.',
            invalid_node_skill_count;
    END IF;

    IF unmapped_allowed_node_count <> 0 THEN
        RAISE EXCEPTION
            'Game Developer roadmap contains % allowed nodes without a skill mapping.',
            unmapped_allowed_node_count;
    END IF;

    IF missing_skill_reference_count <> 0 THEN
        RAISE EXCEPTION
            'Game Developer roadmap references % missing skills. Run shared-skills.seed.sql first.',
            missing_skill_reference_count;
    END IF;

    IF min_category_skill_count < 12 OR max_category_skill_count > 16 THEN
        RAISE EXCEPTION
            'Game Developer roadmap skill categories must remain near 15 skills; observed range %-% across % categories.',
            min_category_skill_count,
            max_category_skill_count,
            category_count;
    END IF;

    RAISE NOTICE
        'Game Developer seed complete. LocalSkills: %, RoadmapSkills: %, SkillCategories: % (%-% each), Resources: %, Nodes: %, NodeSkills: %, NodeResources: %, Edges: %, RequiredTrackableHours: %, AllTrackableHours: %, RoadmapEstimatedHours: 420',
        local_skill_count,
        roadmap_skill_count,
        category_count,
        min_category_skill_count,
        max_category_skill_count,
        resource_count,
        node_count,
        node_skill_count,
        node_resource_count,
        edge_count,
        required_trackable_hours,
        all_trackable_hours;
END $$;

COMMIT;
